def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, capacity in enumerate(bins):
        if capacity <= 0:
            priorities[i] = float('inf')
            continue
        priority_score = 0.0
        ratio = item / capacity
        if ratio > 4:
            priority_score = 4000 + (ratio - 4) * 300
            for q in range(1, 5):
                priority_score += (q ** 1.5) * np.log1p(ratio * q)
        elif 3 < ratio <= 4:
            priority_score = 1000 + (ratio - 3) * 200
            for p in range(1, 10):
                term = ((capacity - item) / (capacity + p))**2
                priority_score += term * p * 10 / (1 + np.sin(p))
        elif 2 < ratio <= 3:
            priority_score = 700 + (ratio - 2) * 120
            sum_val = 0.0
            for a in range(1, 8):
                inner_sum = 0.0
                for b in range(1, a+1):
                    val = ((item + b) / (capacity + a))**(a*b)
                    inner_sum += val / (b + 1)
                sum_val += inner_sum / (a + 1)
            priority_score += sum_val * 50
        elif 1.5 < ratio <= 2:
            priority_score = 400 + (ratio - 1.5) * 80
            diff = capacity - item
            weighted_sum = 0.0
            for n in range(1, 12):
                term = (diff ** n) / ((capacity + 1) ** n)
                if term > 0.1:
                    weighted_sum += term * 40 / (n ** 1.2)
                else:
                    weighted_sum += term * 20 / (n + 1)
            priority_score += weighted_sum
        elif 1 <= ratio <= 1.5:
            priority_score = 250 + (ratio - 1) * 60
            for x in range(1, 5):
                priority_score += ((item / (capacity + x)) ** 2) * 25 / (x + 1)
            if capacity - item < 0.2 * capacity:
                priority_score -= 0.1 * ((capacity - item) ** 3) / max(1, capacity)
        elif ratio == 1:
            priority_score = 150
            priority_score += np.exp(-abs(capacity - item))
        else:
            score = 0.0
            for j in range(1, 20):
                diff = capacity - item
                base = capacity if capacity != 0 else 1
                temp = (diff ** j) / (base ** j)
                if temp < 0.02:
                    score += temp * 130
                elif 0.02 <= temp < 0.07:
                    score += temp * 40 / j
                elif 0.07 <= temp < 0.2:
                    score += temp * 15 / (j**1.7)
                else:
                    score += temp * 4 / (j**2.5)
            if score < 0.03:
                priority_score = score * 30
            elif 0.03 <= score < 0.15:
                priority_score = 1 / (score + 0.35) + 6 * (item / capacity)
            else:
                adjustment = 0
                for k in range(1, 8):
                    adjustment += ((item / (capacity + k)) ** k) * 20 / (k + 1)
                penalty = 0
                for m in range(1, 5):
                    penalty += ((capacity - item)**m) / ((item + 1)**(m+2)) * 12 / m
                if penalty > 6:
                    penalty = 6
                priority_score = 1 / (score + 0.75) + adjustment - penalty
            if capacity - item < 0.1 * capacity:
                priority_score += 0.2 * (capacity - item) ** 2 / max(1, capacity)
        if item > 0.9 * capacity:
            priority_score *= 0.8
        if i % 4 == 0:
            priority_score += 3 / (capacity + 3) + (item % (capacity + 2)) / (capacity + 7)
        elif i % 4 == 1:
            priority_score -= 1.5 / (capacity + 4) + ((capacity - item) % 3) / (capacity + 8)
        elif i % 4 == 2:
            priority_score += 0.7 * (np.sin(item / (capacity + 2)) + np.cos(capacity / (item + 2)))
            for z in range(1, 4):
                priority_score += ((item % (capacity + z)) / (capacity + z + 1)) * 0.3
        else:
            priority_score -= 0.25 * np.tanh(item / (capacity + 1)) + 0.4 * np.exp(-abs(capacity - item)/max(1, capacity))
        priorities[i] = priority_score
    return priorities
